const DirectorWorkflow = () => {
  const [activeStep, setActiveStep] = useState(null);
  const [animating, setAnimating] = useState(false);
  const [queryType, setQueryType] = useState('simple');
  const [flowPath, setFlowPath] = useState([]);
  const [showMetrics, setShowMetrics] = useState(true);

  const runAnimation = () => {
    setAnimating(true);
    setFlowPath([]);
    const path = CONFIG.flows[queryType];

    path.forEach((stepId, i) => {
      setTimeout(() => {
        setActiveStep(stepId);
        setFlowPath(prev => [...prev, stepId]);
        if (i === path.length - 1) {
          setTimeout(() => setAnimating(false), 500);
        }
      }, i * 400);
    });
  };

  const isInPath = (stepId) => flowPath.includes(stepId);
  const isActive = (stepId) => activeStep === stepId;

  const getStatusColor = (status) => {
    switch(status) {
      case 'stable': return '#22c55e';
      case 'needs_work': return '#f59e0b';
      case 'broken': return '#ef4444';
      case 'planned': return '#6366f1';
      default: return '#6b7280';
    }
  };

  const getStepStyle = (step) => {
    const base = {
      position: 'absolute',
      left: step.x + 200,
      top: step.y,
      width: 160,
      padding: '12px 16px',
      borderRadius: 8,
      textAlign: 'center',
      cursor: 'pointer',
      transition: 'all 0.3s ease',
      fontFamily: "'JetBrains Mono', monospace",
      fontSize: 12,
    };

    if (isActive(step.id)) {
      return {
        ...base,
        background: 'linear-gradient(135deg, #a855f7 0%, #7c3aed 100%)',
        color: '#fff',
        boxShadow: '0 0 30px rgba(168, 85, 247, 0.6)',
        transform: 'scale(1.08)',
        border: '2px solid #c084fc',
      };
    }

    if (isInPath(step.id)) {
      return {
        ...base,
        background: 'rgba(168, 85, 247, 0.15)',
        color: '#e9d5ff',
        border: `2px solid ${getStatusColor(step.status)}`,
        boxShadow: `0 2px 10px ${getStatusColor(step.status)}33`,
      };
    }

    return {
      ...base,
      background: 'rgba(30, 30, 40, 0.8)',
      color: '#a1a1aa',
      border: '1px solid rgba(100, 100, 120, 0.3)',
    };
  };

  const renderConnections = () => (
    <svg style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', pointerEvents: 'none' }}>
      <defs>
        <marker id="arrow" markerWidth="10" markerHeight="7" refX="9" refY="3.5" orient="auto">
          <polygon points="0 0, 10 3.5, 0 7" fill="#6b7280" />
        </marker>
        <marker id="arrow-active" markerWidth="10" markerHeight="7" refX="9" refY="3.5" orient="auto">
          <polygon points="0 0, 10 3.5, 0 7" fill="#a855f7" />
        </marker>
      </defs>
      {CONFIG.connections.map(([from, to, type], i) => {
        const fromStep = CONFIG.steps[from];
        const toStep = CONFIG.steps[to];
        if (!fromStep || !toStep) return null;

        const fromX = fromStep.x + 280;
        const fromY = fromStep.y + 40;
        const toX = toStep.x + 280;
        const toY = toStep.y;

        const isActiveConn = isInPath(from) && isInPath(to);

        if (type === 'local' && queryType !== 'simple') return null;
        if (type === 'delegate' && queryType === 'simple') return null;

        const pathD = fromStep.isDecision 
          ? `M ${fromX} ${fromY} C ${fromX} ${fromY + 40}, ${toX} ${toY - 40}, ${toX} ${toY}`
          : `M ${fromX} ${fromY} L ${toX} ${toY}`;

        return (
          <path
            key={i}
            d={pathD}
            fill="none"
            stroke={isActiveConn ? '#a855f7' : '#4b5563'}
            strokeWidth={isActiveConn ? 2.5 : 1.5}
            strokeDasharray={isActiveConn ? 'none' : '4 4'}
            markerEnd={isActiveConn ? 'url(#arrow-active)' : 'url(#arrow)'}
          />
        );
      })}
    </svg>
  );

  const { metrics } = CONFIG;

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(180deg, #0a0a0f 0%, #111118 50%, #0d0d12 100%)',
      padding: 24,
      fontFamily: "'Inter', system-ui, sans-serif",
    }}>
      {/* Header */}
      <div style={{ textAlign: 'center', marginBottom: 24 }}>
        <h1 style={{ fontSize: 24, fontWeight: 600, color: '#f4f4f5', marginBottom: 4 }}>
          Director LLM Workflow
        </h1>
        <p style={{ color: '#71717a', fontSize: 13 }}>
          v{CONFIG.version} • {CONFIG.lastUpdated}
        </p>
      </div>

      {/* Metrics Bar */}
      {showMetrics && (
        <div style={{
          display: 'flex',
          justifyContent: 'center',
          gap: 16,
          marginBottom: 24,
          flexWrap: 'wrap',
        }}>
          {[
            { label: 'Local Speed', value: `${metrics.localTokensPerSec}/${metrics.targetTokensPerSec} tok/s`, color: metrics.localTokensPerSec < 10 ? '#f59e0b' : '#22c55e' },
            { label: 'Memory Nodes', value: metrics.memoryNodes.toLocaleString(), color: '#a855f7' },
            { label: 'QA Pass', value: `${(metrics.qaPassRate * 100).toFixed(0)}%`, color: metrics.qaPassRate < 0.5 ? '#ef4444' : '#22c55e' },
            { label: 'VK Verdict', value: metrics.vkVerdict, color: metrics.vkVerdict === 'REPLICANT' ? '#ef4444' : '#22c55e' },
          ].map((m, i) => (
            <div key={i} style={{
              background: 'rgba(30, 30, 40, 0.8)',
              padding: '8px 16px',
              borderRadius: 8,
              border: '1px solid rgba(100, 100, 120, 0.3)',
              textAlign: 'center',
            }}>
              <div style={{ fontSize: 10, color: '#71717a', marginBottom: 2 }}>{m.label}</div>
              <div style={{ fontSize: 14, fontWeight: 600, color: m.color, fontFamily: "'JetBrains Mono', monospace" }}>{m.value}</div>
            </div>
          ))}
        </div>
      )}

      {/* Controls */}
      <div style={{ display: 'flex', justifyContent: 'center', gap: 12, marginBottom: 24, flexWrap: 'wrap' }}>
        {Object.keys(CONFIG.flows).map(type => (
          <button
            key={type}
            onClick={() => { setQueryType(type); setFlowPath([]); setActiveStep(null); }}
            style={{
              padding: '8px 16px',
              borderRadius: 6,
              border: 'none',
              cursor: 'pointer',
              fontFamily: "'JetBrains Mono', monospace",
              fontSize: 11,
              background: queryType === type ? 'linear-gradient(135deg, #a855f7, #7c3aed)' : 'rgba(30, 30, 40, 0.8)',
              color: queryType === type ? '#fff' : '#a1a1aa',
            }}
          >
            {type.toUpperCase()}
            <span style={{ display: 'block', fontSize: 9, opacity: 0.7 }}>
              {CONFIG.queryExamples[type]}
            </span>
          </button>
        ))}
        <button
          onClick={runAnimation}
          disabled={animating}
          style={{
            padding: '8px 20px',
            borderRadius: 6,
            border: 'none',
            cursor: animating ? 'wait' : 'pointer',
            background: '#22c55e',
            color: '#fff',
            fontWeight: 600,
            fontSize: 12,
          }}
        >
          {animating ? '● Running...' : '▶ Run Flow'}
        </button>
      </div>

      {/* Flow Diagram */}
      <div style={{
        position: 'relative',
        width: 560,
        height: 880,
        margin: '0 auto',
        background: 'rgba(20, 20, 28, 0.5)',
        borderRadius: 16,
        border: '1px solid rgba(100, 100, 120, 0.2)',
      }}>
        {renderConnections()}

        {/* Path Labels */}
        <div style={{
          position: 'absolute', left: 80, top: 400,
          color: queryType === 'simple' ? '#22c55e' : '#4b5563',
          fontSize: 11, fontWeight: 600, fontFamily: "'JetBrains Mono', monospace",
        }}>LOCAL PATH</div>
        <div style={{
          position: 'absolute', left: 420, top: 400,
          color: queryType !== 'simple' ? '#f59e0b' : '#4b5563',
          fontSize: 11, fontWeight: 600, fontFamily: "'JetBrains Mono', monospace",
        }}>DELEGATE PATH</div>

        {/* Render Steps */}
        {Object.entries(CONFIG.steps).map(([id, step]) => (
          <div
            key={id}
            style={getStepStyle({ ...step, id })}
            onClick={() => setActiveStep(id)}
          >
            <div style={{ fontWeight: 500, marginBottom: step.desc ? 4 : 0 }}>
              {step.label}
            </div>
            {step.desc && (
              <div style={{ fontSize: 10, opacity: 0.7 }}>{step.desc}</div>
            )}
            {step.status && step.status !== 'stable' && (
              <div style={{
                position: 'absolute', top: -6, right: -6,
                width: 12, height: 12, borderRadius: '50%',
                background: getStatusColor(step.status),
              }} />
            )}
          </div>
        ))}

        {/* Threshold Indicator */}
        <div style={{
          position: 'absolute', left: 380, top: 335,
          background: 'rgba(30, 30, 40, 0.9)',
          padding: '8px 12px', borderRadius: 6,
          border: '1px solid rgba(100, 100, 120, 0.3)',
          fontFamily: "'JetBrains Mono', monospace", fontSize: 10,
        }}>
          <div style={{ color: '#e9d5ff', fontWeight: 500, marginBottom: 4 }}>Threshold</div>
          <div><span style={{ color: '#22c55e' }}>≤ {CONFIG.complexityThreshold}</span> → Local</div>
          <div><span style={{ color: '#f59e0b' }}>&gt; {CONFIG.complexityThreshold}</span> → Delegate</div>
        </div>
      </div>

      {/* Info Panel */}
      {activeStep && CONFIG.steps[activeStep] && (
        <div style={{
          maxWidth: 560, margin: '24px auto 0', padding: 20,
          background: 'rgba(30, 30, 40, 0.6)', borderRadius: 12,
          border: '1px solid rgba(168, 85, 247, 0.3)',
        }}>
          <div style={{ fontSize: 14, fontWeight: 600, color: '#e9d5ff', marginBottom: 8, fontFamily: "'JetBrains Mono', monospace" }}>
            {CONFIG.steps[activeStep].label}
            {CONFIG.steps[activeStep].status && (
              <span style={{ marginLeft: 8, fontSize: 10, color: getStatusColor(CONFIG.steps[activeStep].status) }}>
                ● {CONFIG.steps[activeStep].status}
              </span>
            )}
          </div>
          <div style={{ fontSize: 13, color: '#a1a1aa', lineHeight: 1.6 }}>
            {CONFIG.descriptions[activeStep] || CONFIG.steps[activeStep].desc}
          </div>
        </div>
      )}

      {/* Legend */}
      <div style={{
        display: 'flex', justifyContent: 'center', gap: 16, marginTop: 24,
        fontSize: 10, color: '#71717a', fontFamily: "'JetBrains Mono', monospace",
      }}>
        {[
          { label: 'Stable', color: '#22c55e' },
          { label: 'Needs Work', color: '#f59e0b' },
          { label: 'Broken', color: '#ef4444' },
          { label: 'Planned', color: '#6366f1' },
        ].map((s, i) => (
          <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
            <div style={{ width: 8, height: 8, borderRadius: '50%', background: s.color }} />
            {s.label}
          </div>
        ))}
      </div>
    </div>
  );
};

export default DirectorWorkflow;
```

**What's new:**

1. **CONFIG object at top** - edit steps, flows, metrics, descriptions all in one place
2. **Status indicators** - `stable` (green), `needs_work` (yellow), `broken` (red), `planned` (purple)
3. **Metrics bar** - shows current performance (local speed, memory nodes, QA pass rate, VK verdict)
4. **Future iterations section** - uncomment blocks to simulate v2.1, v2.2, v3.0 changes
5. **Version/date tracking** - visible in header

to add a new step, just add it to `CONFIG.steps` and update `CONFIG.flows` and `CONFIG.connections`. the component handles the rest.

